func (u *InboundUpsertBulk) Update(set func(*InboundUpsert)) *InboundUpsertBulk {
	u.create.conflict = append(u.create.conflict, sql.ResolveWith(func(update *sql.UpdateSet) {
		set(&InboundUpsert{UpdateSet: update})
	}))
	return u
}

